275→     * safe, as code in other threads could open or close
276→     * the collection while the reference is held. [withCol]
277→     * is a better alternative.
278→     */
279→    fun getColUnsafe(): Collection {
280→        return logUIHangs {
281→            blockForQueue {
282→                ensureOpenInner()
283→                collection!!
284→            }
285→        }
