288→    /**
289→     Execute [block]. If it takes more than 100ms of real time, Timber an error like:
290→     > Blocked main thread for 2424ms: com.ichi2.anki.DeckPicker.onCreateOptionsMenu(DeckPicker.kt:624)
291→     */
292→    // using TimeManager breaks a sched test that makes assumptions about the time, so we
293→    // access the time directly
294→    @SuppressLint("DirectSystemCurrentTimeMillisUsage")
295→    private fun <T> logUIHangs(block: () -> T): T {
296→        val start = System.currentTimeMillis()
297→        return block().also {
298→            val elapsed = System.currentTimeMillis() - start
299→            if (Threads.isOnMainThread && elapsed > 100) {
300→                val stackTraceElements = Thread.currentThread().stackTrace
301→                // locate the probable calling file/line in the stack trace, by filtering
302→                // out our own code, and standard dalvik/java.lang stack frames
303→                val caller = stackTraceElements.filter {
304→                    val klass = it.className
305→                    val toCheck = listOf(
306→                        "CollectionManager",
307→                        "dalvik",
308→                        "java.lang",
309→                        "CollectionHelper",
310→                        "AnkiActivity"
311→                    )
312→                    for (text in toCheck) {
313→                        if (text in klass) {
314→                            return@filter false
315→                        }
316→                    }
317→                    true
318→                }.first()
319→                Timber.w("blocked main thread for %dms:\n%s", elapsed, caller)
320→            }
321→        }
322→    }
