419→    private inner class UndoList {
420→        private val mList: MutableList<WhiteboardAction> = ArrayList()
421→        fun add(action: WhiteboardAction) {
422→            mList.add(action)
423→        }
424→
425→        fun clear() {
426→            mList.clear()
427→        }
428→
