        val redoIcon = menu.findItem(R.id.action_redo)
        redoIcon.setEnabled(redoEnabled).iconAlpha = alphaRedo
        if (redoIcon.actionView != null) {
            redoIcon.actionView!!.isEnabled = redoEnabled
        }
        if (colIsOpenUnsafe()) {
            if (mShowWhiteboard && whiteboard?.redoEmpty() == false) {
                redoIcon.title = resources.getString(R.string.redo) // We don't have a specific "Redo stroke" string, using "Redo"
            } else if (getColUnsafe.redoAvailable()) {
                redoIcon.title = getColUnsafe.redoLabel()
            } else {
                redoIcon.title = resources.getString(R.string.redo)
            }
        }
